+    fn arc_access(state: &mut ArcState, key: BlockNumber) {
+        if state.resident.contains_key(&key) {
+            state.on_hit(key);
+        } else {
+            state.on_miss_or_ghost_hit(key);
+            state.resident.insert(key, vec![0_u8]);
